resources.preRequestScript:
const runId = Date.now().toString();
const now = Date.now();
const sessionStart = new Date(now + 5 * 60 * 1000);
const sessionEnd = new Date(sessionStart.getTime() + 60 * 60 * 1000);
insomnia.baseEnvironment.set('run_id', runId);
insomnia.baseEnvironment.set('session_start_at', sessionStart.toISOString());
insomnia.baseEnvironment.set('session_end_at', sessionEnd.toISOString());
insomnia.baseEnvironment.set('window_from', new Date(now - 60 * 60 * 1000).toISOString());
insomnia.baseEnvironment.set('window_to', new Date(now + 2 * 60 * 60 * 1000).toISOString());

resources.afterResponseScript:
const body = insomnia.response.json();
insomnia.test('asynchronous export A is accepted as PENDING', () => { insomnia.expect(insomnia.response.code).to.eql(202); insomnia.expect(body.status).to.eql('PENDING'); insomnia.expect(body.data_cutoff_at).to.eql(null); });
if (insomnia.response.code === 202) insomnia.baseEnvironment.set('research_export_a_id', body.id);

const body = insomnia.response.json();
insomnia.test('independent research export B is accepted', () => { insomnia.expect(insomnia.response.code).to.eql(202); insomnia.expect(body.status).to.eql('PENDING'); });
if (insomnia.response.code === 202) insomnia.baseEnvironment.set('research_export_b_id', body.id);

const body = insomnia.response.json();
insomnia.test('administrative Parquet export is accepted', () => { insomnia.expect(insomnia.response.code).to.eql(202); insomnia.expect(body.dataset_type).to.eql('OPERATIONAL_CHARGING_SESSIONS'); insomnia.expect(body.export_profile).to.eql('ADMINISTRATIVE'); insomnia.expect(body.format).to.eql('PARQUET'); });
if (insomnia.response.code === 202) insomnia.baseEnvironment.set('sessions_export_id', body.id);

const body = insomnia.response.json();
insomnia.test('analytical occupancy export is accepted', () => { insomnia.expect(insomnia.response.code).to.eql(202); insomnia.expect(body.dataset_type).to.eql('ANALYTICAL_OCCUPANCY'); });
if (insomnia.response.code === 202) insomnia.baseEnvironment.set('occupancy_export_id', body.id);

const body = insomnia.response.json();
const expected = ['research_export_a_id','research_export_b_id','sessions_export_id','occupancy_export_id'].map(name => insomnia.baseEnvironment.get(name));
const own = body.items.filter(item => expected.includes(item.id));
insomnia.test('list exposes all four completed retained artifacts', () => { insomnia.expect(insomnia.response.code).to.eql(200); insomnia.expect(body.limit).to.eql(50); insomnia.expect(body.offset).to.eql(0); insomnia.expect(own).to.have.length(4); own.forEach(item => { insomnia.expect(item.status).to.eql('COMPLETED'); insomnia.expect(item.artifact_available).to.eql(true); }); });

const body = insomnia.response.json();
const id = insomnia.baseEnvironment.get('sessions_export_id');
insomnia.test('completion event carries non-sensitive export metadata', () => { insomnia.expect(insomnia.response.code).to.eql(200); insomnia.expect(body).to.have.length(1); insomnia.expect(body[0].event_type).to.eql('dataset-export.completed'); insomnia.expect(body[0].aggregate_id).to.eql(id); insomnia.expect(body[0].producer_module).to.eql('datasets'); insomnia.expect(body[0].payload.dataset_export_id).to.eql(id); insomnia.expect(body[0].payload.row_count).to.eql(1); });

const body = insomnia.response.json();
const paths = body.paths;
const schemas = body.components.schemas;
insomnia.test('OpenAPI exposes only the documented Dataset Export surface', () => { insomnia.expect(insomnia.response.code).to.eql(200); insomnia.expect(paths['/dataset-exports'].post).to.be.an('object'); insomnia.expect(paths['/dataset-exports'].get).to.be.an('object'); insomnia.expect(paths['/dataset-exports/{dataset_export_id}'].get).to.be.an('object'); insomnia.expect(paths['/dataset-exports/{dataset_export_id}/download'].get.responses['200'].content['application/zip']).to.be.an('object'); insomnia.expect(schemas.DatasetType.enum).to.eql(['OPERATIONAL_CHARGING_SESSIONS','OPERATIONAL_TELEMETRY','ANALYTICAL_OCCUPANCY']); insomnia.expect(schemas.ExportProfile.enum).to.eql(['ADMINISTRATIVE','RESEARCH']); insomnia.expect(schemas.ExportFormat.enum).to.eql(['CSV','PARQUET']); });
